import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { AlertService } from 'src/app/core/services/alert.service';
import { ClientService } from 'src/app/core/services/client.service';
import { LoanApplicationsService } from 'src/app/core/services/loan-applications.service';
import { ReferencesService } from 'src/app/core/services/references.service';
import { ClientInfo } from 'src/app/views/Models/Client/ClientInfo';
import { LoanRejection } from 'src/app/views/Models/Loan/LoanRejection';
import { LoanRejectionParent } from 'src/app/views/Models/Loan/Rejection';
import { SearchResult } from 'src/app/views/Models/References/SearchResult';
import { StaticRef } from 'src/app/views/Models/References/StaticRef';

interface LoanRejectionData {
  loanRejection: LoanRejection[] | undefined;
  loanRejectionParent: LoanRejectionParent[] | undefined;
}

@Component({
  selector: 'app-client-dealing-status-maintenance',
  templateUrl: './client-dealing-status-maintenance.page.html',
  styleUrls: ['./client-dealing-status-maintenance.page.css'],
})
export class ClientDealingsStatusMaintenancePage implements OnInit {
  showLoader: boolean = false;
  isSearching: boolean = true;
  selectedClient: SearchResult;
  clientInfo: ClientInfo;
  clientDealingStatusTypes: StaticRef[];
  clientDealingStatusForm: FormGroup = this.formBuilder.group({
    dealingStatus: [null, [Validators.required]],
    parentRejectionCode: [null, [Validators.required]],
    loanRejectionCode: [null, [Validators.required]],
  });
  loanRejectionObject: LoanRejectionData = {
    loanRejection: [],
    loanRejectionParent: [],
  };
  constructor(private formBuilder: FormBuilder, private referenceService: ReferencesService, private loanApplicationService: LoanApplicationsService, private clientService: ClientService, private alertService: AlertService) { }

  async ngOnInit() {
    this.clientDealingStatusTypes = await this.referenceService.getClientDealingStatus();
    this.loanRejectionObject.loanRejectionParent =
      await this.loanApplicationService.getRejectionRefParent();
    console.log(this.loanRejectionObject.loanRejectionParent)
  }

  clientSelected(event: SearchResult): void {
    this.selectedClient = event;
    //this.isSearching = false;
    this.clientService.getClientByClientKey(event.client_key).then((data) => {
      this.clientInfo = data;
      if (data.client_performance == 1) this.fetchChildLoanRejectionReasons(data?.parent_rej_code.toString())
      this.clientDealingStatusForm = this.formBuilder.group({
        dealingStatus: [data.client_performance.toString(), [Validators.required]],
        parentRejectionCode: [data.client_performance == 0 ? null : data.parent_rej_code, [Validators.required]],
        loanRejectionCode: [data.client_performance == 0 ? null : data.client_rej_code.toString(), [Validators.required]],
      });
      console.log('clientInfo', this.clientInfo);
      this.isSearching = false;
      this.showLoader = false;
    }).catch((err) => {
      console.log(err);
      this.isSearching = false;
      this.showLoader = false;
    });
  }

  checker(input: string) {
    if (input == null) return "لا يوجد";
    else {
      if (input.includes("00:00:00")) {
        return input.split(" ")[0];
      } else {
        return input;
      }
    }
  }

  async onParentRejChanged($event) {
    this.fetchChildLoanRejectionReasons($event.detail.value.toString());
  }

  async fetchChildLoanRejectionReasons(parentCode: string) {
    this.loanRejectionObject.loanRejection =
      await this.loanApplicationService.getLoanRejection(
        parentCode
      );
  }

  back() {
    this.isSearching = true;
    this.clientInfo = undefined;
    this.selectedClient = undefined;
  }

  async save() {
    console.log(this.clientInfo.client_key, this.clientDealingStatusForm.value.dealingStatus, this.clientDealingStatusForm.value.dealingStatus == 1 ? this.clientDealingStatusForm.value.loanRejectionCode : null, this.clientInfo.uuc)
    let done = await this.clientService.setClientDealingStatus(this.clientInfo.client_key, this.clientDealingStatusForm.value.dealingStatus, this.clientDealingStatusForm.value.dealingStatus == 1 ? this.clientDealingStatusForm.value.loanRejectionCode : null, this.clientInfo.uuc)
    if (done) {
      this.isSearching = true;
      this.clientInfo = undefined;
      this.selectedClient = undefined;
    }
    else {
      await this.alertService.showAlertError(
        "حدثت مشكلة أثناء تحديث حالة التعامل مع العميل",
        false
      );
    }
  }
}
